def gen(rng, size):
    import string
    out = [rng.choice(string.ascii_lowercase)]
    length = 1
    for _ in range(rng.randint(1, max(1, size))):
        if rng.random() < 0.5 and length < 5000:
            d = rng.randint(2, 4)
            if length * d <= 20000:
                out.append(str(d))
                length *= d
            else:
                out.append(rng.choice(string.ascii_lowercase))
                length += 1
        else:
            out.append(rng.choice(string.ascii_lowercase))
            length += 1
    k = rng.randint(1, length)
    return [''.join(out), k]

