class Solution:
    def decodeAtIndex(self, s, k):
        tape = []
        for ch in s:
            if ch.isdigit():
                tape = tape * int(ch)
            else:
                tape.append(ch)
            if len(tape) >= k:
                return tape[k - 1]
        return tape[k - 1]

