var decodeAtIndex = function(s, k) {
    let size = 0n;
    let kk = BigInt(k);
    for (const ch of s) {
        if (ch >= '0' && ch <= '9') size *= BigInt(ch);
        else size += 1n;
    }
    for (let i = s.length - 1; i >= 0; i--) {
        const ch = s[i];
        kk %= size;
        if (kk === 0n && !(ch >= '0' && ch <= '9')) return ch;
        if (ch >= '0' && ch <= '9') size /= BigInt(ch);
        else size -= 1n;
    }
    return '';
};
